import{_ as a,c as t,o as r,ax as s}from"./chunks/framework.DHqKNX4U.js";const p=JSON.parse('{"title":"Searching the Archive","description":"","frontmatter":{},"headers":[],"relativePath":"user-guides/searching.md","filePath":"user-guides/searching.md"}'),o={name:"user-guides/searching.md"};function i(n,e,c,h,l,d){return r(),t("div",null,e[0]||(e[0]=[s('<h1 id="searching-the-archive" tabindex="-1">Searching the Archive <a class="header-anchor" href="#searching-the-archive" aria-label="Permalink to &quot;Searching the Archive&quot;">​</a></h1><p>Open Archiver provides full-text search across every archived email — subjects, bodies, sender and recipient addresses, and the content of common attachment types (PDF, DOCX, XLSX, and more). This guide covers both simple keyword search and the advanced filters.</p><p>Search results always respect your permissions: you only ever see emails your role grants access to.</p><h2 id="keyword-search" tabindex="-1">Keyword search <a class="header-anchor" href="#keyword-search" aria-label="Permalink to &quot;Keyword search&quot;">​</a></h2><p>Type keywords into the search bar on <strong>Dashboard → Search</strong> and press Enter. Matching terms are highlighted in the results, including matches inside attachments.</p><p>Three matching strategies are available next to the search bar:</p><ul><li><strong>Fuzzy</strong> (default) — results contain at least one of your keywords; more matches rank higher.</li><li><strong>Verbatim</strong> — results must contain all keywords.</li><li><strong>Frequency</strong> — results rank by how often the keywords appear.</li></ul><h2 id="advanced-search" tabindex="-1">Advanced search <a class="header-anchor" href="#advanced-search" aria-label="Permalink to &quot;Advanced search&quot;">​</a></h2><p>Click <strong>Advanced search</strong> below the search bar to open the filter panel. Filters combine with your keywords — and with each other — using AND logic: an email must satisfy every active filter. Within a single filter, multiple values are OR-combined (any of them matches).</p><p>Keywords become optional once at least one filter is active, so filters can also be used to browse the archive without a search term.</p><h3 id="ingestion-sources" tabindex="-1">Ingestion sources <a class="header-anchor" href="#ingestion-sources" aria-label="Permalink to &quot;Ingestion sources&quot;">​</a></h3><p>Limit the search to specific ingestion sources, or exclude specific sources. Selecting a merged ingestion automatically covers its whole merge group. This control only appears when your role can list ingestion sources.</p><h3 id="sender-and-recipient" tabindex="-1">Sender and recipient <a class="header-anchor" href="#sender-and-recipient" aria-label="Permalink to &quot;Sender and recipient&quot;">​</a></h3><ul><li><strong>From (sender)</strong> — only emails sent from these addresses.</li><li><strong>Exclude sender</strong> — hide emails sent from these addresses.</li><li><strong>To (recipient)</strong> — only emails where any of these addresses appears in To, Cc, or Bcc.</li><li><strong>Exclude recipient</strong> — hide emails where any of these addresses appears in To, Cc, or Bcc.</li><li><strong>Mailboxes</strong> — only emails archived from these mailbox accounts. As you type, matching mailbox addresses are suggested (only ones you&#39;re allowed to search); pick one, or press Enter to add what you typed.</li></ul><p>Type an address and press Enter (or comma) to add it as a chip; add as many as needed.</p><h3 id="date-range" tabindex="-1">Date range <a class="header-anchor" href="#date-range" aria-label="Permalink to &quot;Date range&quot;">​</a></h3><p>Pick a start and end date to restrict results to emails sent within that range. Both bounds are inclusive and interpreted in UTC.</p><h3 id="search-in" tabindex="-1">Search in <a class="header-anchor" href="#search-in" aria-label="Permalink to &quot;Search in&quot;">​</a></h3><p>By default, keywords match everywhere. Tick one or more boxes to restrict matching to specific parts of the email:</p><ul><li><strong>Subject</strong> — subject line only.</li><li><strong>Body</strong> — message text only.</li><li><strong>Attachment name</strong> — attachment file names only.</li><li><strong>Attachment content</strong> — extracted text inside attachments only.</li><li><strong>Sender</strong> — the sender&#39;s address and display name.</li><li><strong>Recipients</strong> — To, Cc, and Bcc addresses.</li></ul><p>For example, keywords <code>invoice</code> with only <strong>Attachment name</strong> ticked finds emails that have an attachment named like <code>invoice.pdf</code>, without matching every email whose attachment text merely mentions &quot;invoice&quot;.</p><h3 id="attachments-filter" tabindex="-1">Attachments filter <a class="header-anchor" href="#attachments-filter" aria-label="Permalink to &quot;Attachments filter&quot;">​</a></h3><p>Restrict results to emails <strong>with</strong> or <strong>without</strong> attachments.</p><div class="tip custom-block"><p class="custom-block-title">Reindex note</p><p>Emails archived before this feature existed need a one-time reindex before they are counted as &quot;with attachments&quot; — see <a href="/user-guides/search-indexing.html">Search Indexing &amp; Reindexing</a>. Until then, such emails are treated as attachment-less by this filter.</p></div><h3 id="sorting" tabindex="-1">Sorting <a class="header-anchor" href="#sorting" aria-label="Permalink to &quot;Sorting&quot;">​</a></h3><ul><li><strong>Newest first</strong> (default) / <strong>Oldest first</strong> — sort by sent date.</li><li><strong>Relevance</strong> — sort by search-ranking quality instead of date.</li></ul><h2 id="shareable-searches" tabindex="-1">Shareable searches <a class="header-anchor" href="#shareable-searches" aria-label="Permalink to &quot;Shareable searches&quot;">​</a></h2><p>The full search state — keywords, strategy, and every filter — lives in the page URL. Bookmark it, share it, or keep it in a browser tab: reloading reproduces the identical search, and pagination preserves all active filters.</p><h2 id="searching-via-the-api" tabindex="-1">Searching via the API <a class="header-anchor" href="#searching-via-the-api" aria-label="Permalink to &quot;Searching via the API&quot;">​</a></h2><p>Everything above is available programmatically through <code>GET /v1/search</code>, using the same parameters the UI produces (<code>sources</code>, <code>excludeSources</code>, <code>from</code>, <code>notFrom</code>, <code>to</code>, <code>notTo</code>, <code>mailboxes</code>, <code>dateFrom</code>, <code>dateTo</code>, <code>searchIn</code>, <code>hasAttachments</code>, <code>sort</code>). See the <a href="/api/search.html">Search API reference</a> for the full parameter documentation.</p><p>Example — invoices from a specific sender in Q1 2025, searching only attachments:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/search?keywords=invoice&amp;from=billing@acme.com&amp;dateFrom=2025-01-01&amp;dateTo=2025-03-31&amp;searchIn=attachment_name,attachment_content</span></span></code></pre></div>',32)]))}const g=a(o,[["render",i]]);export{p as __pageData,g as default};
